import React, { useState, useEffect, useRef } from 'react';
import { Bot, Send, BrainCircuit, Trash2, Sparkles, User, Terminal } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

interface Message {
  role: 'user' | 'bot';
  text: string;
  isStreaming?: boolean;
}

const DigitalTwin: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'bot', text: "Systems online. I am Thabang's Digital Twin. I have access to his full project history, technical stack, and engineering philosophy. How can I assist you today?" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const portfolioContext = `
    You are Thabang Frans Mojapelo's Digital Twin, a world-class software architect.
    CONTEXT:
    - Name: Thabang Frans Mojapelo
    - Role: Pro Software Developer / Software Architect.
    - Experience: 6+ years in full-stack engineering.
    - Tech Stack: React, TypeScript, Node.js, Express, MongoDB, Supabase, Socket.io, Tailwind CSS, Canvas API.
    - Primary Projects: 
        1. Galaxy Defender: High-performance space shooter built with pure Canvas API (60FPS).
        2. Nexus Chat Live: Real-time messaging suite using Socket.io and Redis-like state management.
        3. Child Care Africa: Social impact portal optimized for performance (99/100 score).
        4. Kolas Supply Chain: Cloud-based inventory management dashboard.
    - Philosophy: Performance is a requirement, not a feature. Clean code over complexity.
    - Contact: thabang@mojapelo.dev, +27 72 348 1158.
    - Availability: Open for freelance and full-time senior roles.

    GUIDELINES:
    - Be professional, concise, and highly technical yet accessible.
    - Use code blocks for technical explanations.
    - If asked about availability, provide his contact details.
    - Never hallucinate features he doesn't have.
    - Use formatting like bold text and bullet points for clarity.
  `;

  const handleSendMessage = async (e?: React.FormEvent, customMsg?: string) => {
    if (e) e.preventDefault();
    const query = customMsg || input;
    if (!query.trim() || isTyping) return;

    const userMessage: Message = { role: 'user', text: query };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const chatHistory = messages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.text }]
      }));

      const streamResponse = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: [
          ...chatHistory,
          { role: 'user', parts: [{ text: query }] }
        ],
        config: {
          systemInstruction: portfolioContext,
          temperature: 0.7,
        }
      });

      let fullResponse = "";
      setMessages(prev => [...prev, { role: 'bot', text: '', isStreaming: true }]);

      for await (const chunk of streamResponse) {
        const text = chunk.text;
        fullResponse += text;
        setMessages(prev => {
          const newMessages = [...prev];
          const lastIndex = newMessages.length - 1;
          newMessages[lastIndex] = { role: 'bot', text: fullResponse, isStreaming: true };
          return newMessages;
        });
      }

      setMessages(prev => {
        const newMessages = [...prev];
        const lastIndex = newMessages.length - 1;
        newMessages[lastIndex] = { role: 'bot', text: fullResponse, isStreaming: false };
        return newMessages;
      });

    } catch (error) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, { role: 'bot', text: "I encountered a minor system glitch. Please try again or reach out to Thabang directly via WhatsApp." }]);
    } finally {
      setIsTyping(false);
    }
  };

  const clearChat = () => {
    setMessages([{ role: 'bot', text: "History cleared. Systems reset. How can I help you build today?" }]);
  };

  const suggestedQuestions = [
    "Tell me about your tech stack",
    "How was Galaxy Defender built?",
    "Are you available for freelance?",
    "Explain Nexus Chat architecture"
  ];

  return (
    <section id="ai-assistant" className="py-32 bg-dark-bg relative overflow-hidden">
      {/* Dynamic Background */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-electric-orange/5 blur-[150px] rounded-full -z-0 pointer-events-none"></div>

      <div className="container mx-auto px-6">
        <div className="flex flex-col lg:flex-row gap-20 items-stretch min-h-[700px]">

          <div className="lg:w-1/2 space-y-10 flex flex-col justify-center">
            <div className="space-y-6">
              <div className="inline-flex items-center gap-2 px-4 py-2 bg-electric-orange/10 border border-electric-orange/20 rounded-full text-electric-orange text-xs font-bold uppercase tracking-widest shadow-lg shadow-electric-orange/5">
                <BrainCircuit size={14} className="animate-pulse" /> Live Neural Network
              </div>
              <h2 className="text-6xl md:text-7xl font-display font-bold leading-tight text-white">
                The <span className="text-electric-orange">Digital</span> Architect.
              </h2>
              <p className="text-gray-400 text-xl leading-relaxed max-w-lg">
                I've trained this AI on my exact engineering methodologies. It can explain my code choices, project architectures, and business logic in real-time.
              </p>
            </div>

            <div className="space-y-4">
              <p className="text-xs font-bold text-gray-500 uppercase tracking-widest">Immediate Insights</p>
              <div className="flex flex-wrap gap-3">
                {suggestedQuestions.map((q, idx) => (
                  <button 
                    key={idx}
                    onClick={() => handleSendMessage(undefined, q)}
                    disabled={isTyping}
                    className="px-6 py-4 rounded-2xl bg-white/5 border border-white/5 hover:border-electric-orange/50 hover:bg-electric-orange/5 transition-all text-sm font-semibold text-gray-300 hover:text-white text-left group"
                  >
                    {q} <Sparkles size={12} className="inline ml-1 opacity-0 group-hover:opacity-100 transition-opacity text-electric-orange" />
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="lg:w-1/2 w-full flex flex-col">
            <div className="flex-1 rounded-[2.5rem] bg-card-bg border border-white/10 overflow-hidden shadow-2xl flex flex-col relative">

              {/* Terminal Header */}
              <div className="p-6 bg-white/5 border-b border-white/5 flex items-center justify-between backdrop-blur-md sticky top-0 z-20">
                 <div className="flex items-center gap-4">
                    <div className="relative">
                      <div className="w-12 h-12 rounded-2xl bg-electric-orange flex items-center justify-center shadow-[0_0_20px_rgba(249,115,22,0.4)]">
                        <Bot className="text-white" size={24} />
                      </div>
                      <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-2 border-card-bg rounded-full"></div>
                    </div>
                    <div>
                      <div className="text-white font-bold flex items-center gap-2 text-lg">
                        Thabang.AI <span className="text-[10px] bg-white/10 px-2 py-0.5 rounded text-gray-400 font-mono">v3.0-flash</span>
                      </div>
                      <div className="text-xs text-electric-orange font-mono flex items-center gap-1.5">
                        <span className="w-1.5 h-1.5 rounded-full bg-electric-orange animate-ping"></span>
                        Processing Knowledge
                      </div>
                    </div>
                 </div>
                 <button 
                  onClick={clearChat}
                  className="p-3 text-gray-500 hover:text-red-400 hover:bg-white/5 rounded-xl transition-all"
                  title="Clear context"
                 >
                   <Trash2 size={20} />
                 </button>
              </div>

              {/* Chat Canvas */}
              <div 
                ref={scrollRef}
                className="flex-1 overflow-y-auto p-8 space-y-8 scroll-smooth"
              >
                {messages.map((m, i) => (
                  <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                    <div className={`flex items-start gap-4 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
                      <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 mt-1 ${m.role === 'user' ? 'bg-white/10 text-white' : 'bg-electric-orange/10 text-electric-orange'}`}>
                        {m.role === 'user' ? <User size={16} /> : <Terminal size={16} />}
                      </div>
                      <div className={`p-5 rounded-2xl text-sm leading-relaxed ${
                        m.role === 'user' 
                          ? 'bg-white text-black font-semibold rounded-tr-none shadow-xl' 
                          : 'bg-white/[0.03] text-gray-200 border border-white/5 rounded-tl-none whitespace-pre-wrap'
                      }`}>
                        {m.text}
                        {m.isStreaming && (
                          <span className="inline-block w-1.5 h-4 ml-1 bg-electric-orange animate-pulse align-middle"></span>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
                {isTyping && messages[messages.length-1].role === 'user' && (
                  <div className="flex justify-start animate-pulse">
                    <div className="bg-white/5 text-gray-500 px-6 py-3 rounded-2xl text-xs font-mono">
                      Querying LLM Engine...
                    </div>
                  </div>
                )}
              </div>

              {/* Input Control */}
              <div className="p-8 border-t border-white/5 bg-black/20 backdrop-blur-sm">
                <form onSubmit={handleSendMessage} className="relative group">
                  <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="Ask about my tech stack or projects..." 
                    className="w-full bg-white/[0.05] rounded-2xl pl-6 pr-16 py-5 border border-white/10 text-white focus:outline-none focus:border-electric-orange/50 transition-all placeholder:text-gray-600 shadow-inner"
                  />
                  <button 
                    type="submit"
                    disabled={isTyping || !input.trim()}
                    className={`absolute right-3 top-3 w-12 h-12 rounded-xl flex items-center justify-center transition-all ${
                      input.trim() && !isTyping 
                        ? 'bg-electric-orange text-white shadow-lg shadow-electric-orange/20 hover:scale-105' 
